import{_ as t,o as a,c as r,a3 as o}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Documentation Governance","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Documentation Governance | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/documentation-governance"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Documentation Governance | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/documentation-governance"}]]},"headers":[],"relativePath":"developer-guide/documentation-governance.md","filePath":"developer-guide/documentation-governance.md","lastUpdated":1784905729000}'),n={name:"developer-guide/documentation-governance.md"};function d(s,e,i,l,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="documentation-governance" tabindex="-1">Documentation Governance <a class="header-anchor" href="#documentation-governance" aria-label="Permalink to &quot;Documentation Governance&quot;">тАЛ</a></h1><p>SaleOS treats documentation as part of the product. A change is <strong>not complete</strong> until <strong>code</strong>, <strong>tests</strong>, and <strong>documentation</strong> are updated together.</p><p>Canonical site: <a href="https://docs.saleos.app" target="_blank" rel="noreferrer">docs.saleos.app</a>. Source repository: <strong>SaaS-Docs</strong>.</p><hr><h2 id="same-pr-rule" tabindex="-1">Same-PR rule <a class="header-anchor" href="#same-pr-rule" aria-label="Permalink to &quot;Same-PR rule&quot;">тАЛ</a></h2><p>Every feature, bug fix, enhancement, refactor, architectural change, configuration change, deployment change, migration, permission update, API change, CI/CD update, and operational change <strong>must</strong> update the appropriate documentation <strong>in the same Pull Request</strong> as the code (or in a linked Docs PR merged in the same release window when the change spans three repos).</p><p>Do not open a follow-up тАЬdocs laterтАЭ PR as the default path. If Docs must ship separately (Frontend/Backend-only repos), open the Docs PR in the <strong>same milestone</strong> and block release until it lands.</p><hr><h2 id="definition-of-done" tabindex="-1">Definition of done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of done&quot;">тАЛ</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Required</th></tr></thead><tbody><tr><td>Code</td><td>Merged implementation on the correct repo(s)</td></tr><tr><td>Tests</td><td>Pest and/or Playwright (or equivalent) covering the change</td></tr><tr><td>Documentation</td><td>Matching VitePress pages + <a href="/changelog/">CHANGELOG</a> entry when user/operator/developer-visible</td></tr></tbody></table><p>Platform freeze still applies тАФ docs must not invent parallel architecture. See <a href="/getting-started/platform-freeze">Platform Freeze</a>.</p><hr><h2 id="what-to-update-matrix" tabindex="-1">What to update (matrix) <a class="header-anchor" href="#what-to-update-matrix" aria-label="Permalink to &quot;What to update (matrix)&quot;">тАЛ</a></h2><table tabindex="0"><thead><tr><th>Change type</th><th>Update these docs</th></tr></thead><tbody><tr><td>User-visible behavior</td><td>User Guide pages under <code>/user-guide/</code></td></tr><tr><td>API request/response/routes</td><td><code>/api/</code> references</td></tr><tr><td>Schema / migrations</td><td><a href="/developer-guide/database">Database</a> (+ module docs)</td></tr><tr><td>Permissions</td><td>RBAC / permissions references + module guides</td></tr><tr><td>Settings / env vars</td><td>Central/Tenant settings guides + deployment ops</td></tr><tr><td>Deploy / queue / scheduler</td><td><a href="/deployment/">Deployment</a> + <a href="/deployment/upgrade">Upgrade</a></td></tr><tr><td>CI/CD workflows</td><td>Repo README CI section + CHANGELOG if process changes</td></tr><tr><td>Architecture / module rules</td><td><code>/architecture/</code> + developer guides</td></tr><tr><td>Releases / tags</td><td><a href="/deployment/release-process">Release Process</a> + <code>/changelog/vX.Y.Z-platform</code></td></tr><tr><td>Roadmap status</td><td><a href="/getting-started/product-roadmap">Product Roadmap</a></td></tr></tbody></table><p>Always add a dated note under <a href="/changelog/">CHANGELOG</a> for shippable work.</p><hr><h2 id="three-repo-coordination" tabindex="-1">Three-repo coordination <a class="header-anchor" href="#three-repo-coordination" aria-label="Permalink to &quot;Three-repo coordination&quot;">тАЛ</a></h2><table tabindex="0"><thead><tr><th>Repo</th><th>Role</th></tr></thead><tbody><tr><td><strong>SaaS-Backend</strong></td><td>Implementation + Pest; link Docs paths in PR description</td></tr><tr><td><strong>SaaS-Frontend</strong></td><td>UI/E2E; keep user-facing copy aligned with Docs</td></tr><tr><td><strong>SaaS-Docs</strong></td><td>Canonical narrative, runbooks, changelog, release records</td></tr></tbody></table><p>Platform-scoped releases follow <a href="/deployment/release-process">Release Process</a> (<code>vX.Y.Z-platform</code> on all three).</p><hr><h2 id="pr-checklist-authors" tabindex="-1">PR checklist (authors) <a class="header-anchor" href="#pr-checklist-authors" aria-label="Permalink to &quot;PR checklist (authors)&quot;">тАЛ</a></h2><ul><li>[ ] CHANGELOG delivery notes updated (or release page for platform tags)</li><li>[ ] User Guide updated if operators/end users see a change</li><li>[ ] Developer Guide / API / Database updated if engineers must implement or integrate</li><li>[ ] Deployment / Upgrade / env notes updated if ops steps changed</li><li>[ ] Roadmap status updated if a planned item shipped or was deferred</li><li>[ ] No stale тАЬtag existsтАЭ / test-count claims unless verified</li></ul><hr><h2 id="reviewers" tabindex="-1">Reviewers <a class="header-anchor" href="#reviewers" aria-label="Permalink to &quot;Reviewers&quot;">тАЛ</a></h2><p>Reject or request changes on PRs that ship behavior without Docs when the matrix above requires an update. Prefer blocking merge over тАЬfix docs tomorrow.тАЭ</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">тАЛ</a></h2><ul><li><a href="/developer-guide/module-development">Module Development Standard</a></li><li><a href="/getting-started/product-roadmap#development-principles">Product Roadmap тАФ Development Principles</a></li><li><a href="/deployment/release-process">Release Process</a></li><li><a href="/getting-started/platform-freeze">Platform Freeze</a></li><li><a href="/changelog/">CHANGELOG</a></li></ul>',28)])])}const m=t(n,[["render",d]]);export{u as __pageData,m as default};
